import React from 'react';
import { useState, useEffect } from 'react';

const HostDashboard = () => {
    console.log("Host Dashboard")
    function addProperty() {
        alert("Add Property")
    }
    // const [reservations, setReservations] = useState([]);

    // useEffect(() => {
    //   fetch("http://localhost:9000/reservations")
    //     .then((response) => response.json())
    //     .then((reservations) => {
    //       console.log(reservations);
    //       setReservations(reservations);
    //     })
    //     .catch((err) => {
    //       console.log(err.message);
    //     });
    // }, []);

    const [properties, setProperties] = useState([]);

    useEffect(() => {
      fetch("http://localhost:9000/properties")
        .then((response) => response.json())
        .then((properties) => {
          console.log(properties);
          setProperties(properties);
        })
        .catch((err) => {
          console.log(err.message);
        });
    }, []);

    const mystyle = {
        // color: "white",
        // backgroundColor: "DodgerBlue",
       marginLeft: "500px" 
        // fontFamily: "Arial"
      };

    return (
        <>

            <h1>Host</h1>

            <button style={{mystyle}} type="button" className="btn btn-primary" onClick={addProperty}>Add Property</button>

            <div className="container" style={{ marginTop: '5%' }}>
                <div className="row" >
                    <div className="col-12">
                        <table className="table table-bordered" >
                            <thead>
                                <tr>
                                    <th scope="col">Sr. No.</th>
                                    <th scope="col">Title</th>
                                </tr>
                            </thead>

                            <tbody>
                                {Object.keys(properties).map((key) =>
                                    <tr>
                                        <th scope="row">{key+number(1)}</th>
                                        <td>{properties[key].title}</td>
                                        <td>
                                            <button type="button" className="btn btn-primary"><i className="far" />Review</button>
                                            <button type="button" className="btn btn-danger"><i className="far" />Cancel</button>
                                        </td>
                                    </tr>
                                )}

                            </tbody>
                        </table>
                    </div>
                </div>
            </div>
        </>

    );
}

export default HostDashboard;
